SELECT COUNT(*)
  FROM STOCATCH
 WHERE GATE_CD = #{ses.gateCd}
   AND UUID = #{UUID}
   AND DEL_FLAG = 0

SELECT ECCT.BUYER_CD
	 , ECCT.CONT_NUM
	 , ECCT.CONT_CNT
	 , ECCT.CONT_DESC
	 , (ECCT.CONT_DATE, 'YYYYMMDD') AS CONT_DATE
	 , GETVENDORNAME(ECCT.GATE_CD, ECCT.VENDOR_CD, #{ses.langCd}) AS VENDOR_NM
  FROM STOCECCT ECCT
 WHERE ECCT.GATE_CD  = #{ses.gateCd}
   AND ECCT.CONT_NUM = #{CONT_NUM}
   AND ECCT.CONT_CNT = #{CONT_CNT}

mapper.update:
UPDATE STOCATCH SET
   DEL_FLAG = '1',
   MOD_USER_ID =  #{ses.userId} ,
   MOD_DATE = SYSDATE
 WHERE GATE_CD = #{ses.gateCd}
   AND UUID = #{UUID}
   AND UUID_SQ = #{UUID_SQ}

		UPDATE STOCFILE SET
			FILE_CONTENTS = #{BINARY_FILE_INFO, typeHandler=org.apache.ibatis.type.ByteArrayTypeHandler}
    	 WHERE GATE_CD = #{ses.gateCd}
           AND UUID = #{UUID}
           AND UUID_SQ = #{UUID_SQ}

UPDATE STOCATCH
   SET MOD_DATE    = SYSDATE
   	 , MOD_USER_ID = #{ses.userId}

   	 , FILE_PATH   = #{FILE_PATH}


   	 , FILE_SIZE   = #{FILE_SIZE}


   	 , FILE_EXTENSION = #{EXTENSION}


   	 , REAL_FILE_NM = #{REAL_FILE_NM}


   	 , PR_BUYER_CD = #{PR_BUYER_CD}


   	 , PR_DEPT_CD = #{PR_DEPT_CD}

   	 , HASH_NUM    = #{HASH_NUM}
 WHERE GATE_CD = #{ses.gateCd}
   AND UUID    = #{UUID}
   AND UUID_SQ = #{UUID_SQ}

